barColor.colorFunction:
var hora = new Date().getHours();
 var carga;

 if ([13, 14, 20, 21, 22].indexOf(hora) >= 0) {
     carga = 1.0;
 } else if (hora >= 2 && hora <= 5) {
     carga = 0.4;
 } else {
     carga = 0.7;
 }

 var kw_nom = (13200 * 105 * carga * 3) / 1000 * 0.95;

 if (value >= kw_nom * 0.90 && value <= kw_nom * 1.10) {
     return '#2e7d32'; // Verde
 }
 if (value >= kw_nom * 0.80 && value <= kw_nom * 1.20) {
     return '#f9a825'; // Amarillo
 }
 return '#c62828'; // Rojo

// Color de la gauge según si la potencia activa (kW) está dentro del rango esperado para la hora actual.
 // Verde: ±10% del nominal | Amarillo: ±10-20% | Rojo: fuera de ±20%.
 // El nominal varía con el perfil de carga del simulador (fp=0.95, i_nom=105A,v_fase=13200V).
 // NOTA: new Date() usa la hora del NAVEGADOR del cliente, no la del servidor ThingsBoard.
  // Límites por franja horaria:
 //   Carga 100% (13,14,20,21,22h) → nom=3940kW | Verde: 3546-4334 | Amarillo:3152-4728
 //   Carga  70% (resto del día)   → nom=2758kW | Verde: 2482-3034 | Amarillo:2206-3310
 //   Carga  40% (2-5h)            → nom=1576kW | Verde: 1418-1734 | Amarillo:1261-1891

var hora = new Date().getHours();
  var carga;

  if ([13, 14, 20, 21, 22].indexOf(hora) >= 0) {
      carga = 1.0;
  } else if (hora >= 2 && hora <= 5) {
      carga = 0.4;
  } else {
      carga = 0.7;
  }

  var kva_nom = (13200 * 105 * carga * 3) / 1000; // Sin fp

  if (value >= kva_nom * 0.90 && value <= kva_nom * 1.10) {
      return '#2e7d32'; // Verde
  }
  if (value >= kva_nom * 0.80 && value <= kva_nom * 1.20) {
      return '#f9a825'; // Amarillo
  }
  return '#c62828'; // Rojo

